import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  // 1. Added 'inquiries' to activeTab state
  const [activeTab, setActiveTab] = useState('create'); 
  const [postType, setPostType] = useState('blog'); 
  const [category, setCategory] = useState('Electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]); 
  const [inquiries, setInquiries] = useState([]); // State for Contact Data

  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState(null);

  // 2. Fetch Contact Inquiries function
  const fetchInquiries = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/contact'); // Make sure this endpoint exists
      setInquiries(res.data);
    } catch (err) { console.error("Inquiries fetch failed", err); }
  };

  const fetchItems = async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
    if (activeTab === 'inquiries') fetchInquiries(); // Fetch when tab changes
  }, [activeTab, postType, category]);

  // Handle Delete for Inquiries (Optional but good to have)
  const deleteInquiry = async (id) => {
    if (window.confirm("Delete this inquiry?")) {
      try {
        await axios.delete(`http://localhost:5001/api/admin/contact/${id}`);
        fetchInquiries();
      } catch (err) { alert("Delete failed"); }
    }
  };

  // ... (handleUpdate and handleSubmit logic remains same)

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10 font-sans">

      {/* SIDEBAR - Fixed "Brand Name Kat Raha Hai" by adding mt-12 */}
      <div className="w-80 bg-black text-white p-8 fixed h-full shadow-2xl overflow-y-auto">
        <div className="mt-10 mb-12"> {/* Added more top margin */}
          <h2 className="text-2xl font-black text-orange-500 tracking-tighter leading-none">
            Rhodeotech <br /> 
            <span className="text-white text-4xl">ADMIN</span>
          </h2>
        </div>

        <div className="space-y-2">
          <button onClick={() => setActiveTab('create')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'create' ? 'bg-orange-600 shadow-lg' : 'text-gray-400 hover:text-white'}`}>➕ Create New</button>
          <button onClick={() => setActiveTab('manage')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'manage' ? 'bg-orange-600 shadow-lg' : 'text-gray-400 hover:text-white'}`}>⚙️ Manage All</button>

          {/* 3. New Tab for Contact Inquiries */}
          <button onClick={() => setActiveTab('inquiries')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'inquiries' ? 'bg-orange-600 shadow-lg' : 'text-gray-400 hover:text-white'}`}>📩 Inquiries</button>
        </div>

        {/* Only show selectors for Manage/Create tabs */}
        {(activeTab === 'create' || activeTab === 'manage') && (
          <div className="mt-10 border-t border-gray-800 pt-6 space-y-6">
             <div className="flex bg-gray-900 p-1.5 rounded-xl border border-gray-800">
               <button onClick={() => setPostType('job')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all ${postType === 'job' ? 'bg-white text-black' : 'text-gray-500'}`}>Jobs</button>
               <button onClick={() => setPostType('blog')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all ${postType === 'blog' ? 'bg-white text-black' : 'text-gray-500'}`}>Blogs</button>
             </div>
             {postType === 'blog' && (
               <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full bg-gray-900 text-white p-4 rounded-xl text-sm border border-gray-800 outline-none">
                 <option value="Electronics">Electronics</option>
                 <option value="Electrical">Electrical</option>
                 <option value="Chemical">Chemical</option>
                 <option value="Industries">Industries</option>
               </select>
             )}
          </div>
        )}
      </div>

      {/* MAIN CONTENT AREA */}
      <div className="flex-1 ml-80 p-12">
        {activeTab === 'create' && (
          /* ... Your Create Form Code ... */
          <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm">
             <h1 className="text-5xl font-black italic tracking-tighter text-gray-900 mb-10">Add Content</h1>
             {/* Form code here (same as yours) */}
          </div>
        )}

        {activeTab === 'manage' && (
          /* ... Your Manage All Code ... */
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm">
             <h1 className="text-4xl font-black italic mb-10">Active Repository</h1>
             {/* Items mapping code here (same as yours) */}
          </div>
        )}

        {/* 4. NEW TAB: INQUIRIES DISPLAY */}
        {activeTab === 'inquiries' && (
          <div className="max-w-5xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <div className="mb-10">
              <span className="text-orange-600 font-black text-[10px] uppercase tracking-[0.3em]">Customer Requests</span>
              <h1 className="text-5xl font-black italic tracking-tighter text-gray-900">Contact Inquiries</h1>
            </div>

            <div className="grid gap-6">
              {inquiries.length > 0 ? inquiries.map((iq) => (
                <div key={iq._id} className="p-8 bg-gray-50 rounded-[2.5rem] border border-gray-100 hover:shadow-xl transition-all">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="text-2xl font-black text-gray-900">{iq.fullName}</h3>
                      <p className="text-orange-600 font-bold text-sm">{iq.email}</p>
                    </div>
                    <span className="bg-white px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border border-gray-200">
                      {iq.sector || 'General'}
                    </span>
                  </div>
                  <div className="bg-white p-6 rounded-2xl border border-gray-100 mb-4">
                    <p className="text-gray-600 font-medium italic">"{iq.message}"</p>
                  </div>
                  <div className="flex justify-between items-center">
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Company: {iq.company || 'N/A'}</p>
                    <button onClick={() => deleteInquiry(iq._id)} className="text-red-500 font-black text-[10px] uppercase tracking-widest hover:text-red-700">Delete Record</button>
                  </div>
                </div>
              )) : (
                <p className="text-center py-20 text-gray-300 font-bold uppercase italic">No inquiries found.</p>
              )}
            </div>
          </div>
        )}
      </div>
      {/* ... Edit Modal ... */}
    </div>
  );
};

export default AdminPanel;
